CREATE FUNCTION public.get_baserow_table_row_count(table_id integer) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    row_count BIGINT;
BEGIN
    BEGIN
        EXECUTE 'SELECT COUNT(*) FROM database_table_' || table_id || ' WHERE trashed=false;' INTO row_count;
        RETURN row_count;
    EXCEPTION WHEN OTHERS THEN
        return null;
    END;
end;
$$;


