--
-- Name: row_exists_not_trashed(integer, integer); Type: FUNCTION; Schema: public; Owner: baserow
--

CREATE FUNCTION public.row_exists_not_trashed(p_table_id integer, p_row_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $_$
DECLARE
    table_name text;
    result boolean;
BEGIN
    table_name := 'database_table_' || p_table_id;

    IF NOT EXISTS (
        SELECT 1 FROM pg_class WHERE relname = table_name AND relkind = 'r'
    ) THEN
        RETURN false;
    END IF;

    EXECUTE format(
        'SELECT EXISTS(SELECT 1 FROM %I WHERE id = $1 AND trashed = false)',
        table_name
    ) INTO result USING p_row_id;

    RETURN COALESCE(result, false);
END;
$_$;


ALTER FUNCTION public.row_exists_not_trashed(p_table_id integer, p_row_id integer) OWNER TO baserow;

