CREATE FUNCTION public.try_cast_to_url(input_text text) RETURNS text
    LANGUAGE plpgsql
    AS $_$
BEGIN
    IF input_text ~ '^(?:([a-zA-Z]+):\/\/)?(?:([a-zA-Z0-9._%+-]+)(:[a-zA-Z0-9._%+-]+)?@)?([a-zA-Z0-9.-]+)(?::(\d+))?(\/[^?]*)?(\?.*)?(#.*)?$' THEN
        RETURN input_text;
    ELSE
        RETURN '';
    END IF;
END;
$_$;


